/// <reference types="vitest" />
import react from '@vitejs/plugin-react';
import path from 'path';
import { defineConfig } from 'vite';

export default defineConfig({
  plugins: [react()],
  resolve: {
    alias: {
      '@': path.resolve(__dirname, './src'),
    },
  },
  css: {
    preprocessorOptions: {
      scss: {
        api: 'modern-compiler',
      },
    },
  },
  test: {
    environment: 'jsdom',
    globals: true,
    setupFiles: ['./src/test_setup.ts'],
  },
});

{
  "$schema": "../node_modules/@tauri-apps/cli/config.schema.json",
  "productName": "Raycast Clone",
  "version": "0.1.0",
  "identifier": "com.antoniopresto.raycastclone",
  "build": {
    "frontendDist": "../dist",
    "devUrl": "http://localhost:5173",
    "beforeDevCommand": "bun run dev",
    "beforeBuildCommand": "bun run build"
  },
  "app": {
    "macOSPrivateApi": true,
    "windows": [
      {
        "label": "main",
        "title": "Raycast",
        "width": 750,
        "height": 500,
        "center": true,
        "decorations": false,
        "transparent": true,
        "resizable": false,
        "maximizable": false,
        "fullscreen": false,
        "alwaysOnTop": true,
        "shadow": true,
        "visible": false
      }
    ],
    "security": {
      "csp": null
    }
  },
  "bundle": {
    "active": true,
    "targets": "all",
    "icon": [
      "icons/32x32.png",
      "icons/128x128.png",
      "icons/128x128@2x.png",
      "icons/icon.icns",
      "icons/icon.ico"
    ]
  }
}

/** @type {import("prettier").Config} */
const config = {
  arrowParens: 'avoid',
  bracketSameLine: false,
  bracketSpacing: true,
  singleQuote: true,
  trailingComma: 'all',
  printWidth: 80,
  semi: true,
  tabWidth: 2,
  plugins: [
    '@belt/prettier-plugin',
    'prettier-plugin-organize-imports',
  ],
};

export default config;
